sql:
SELECT station_name, capacity
FROM stations
WHERE capacity = (SELECT MAX(capacity) FROM stations);

SELECT street_name, length
FROM streets
WHERE length = (SELECT MAX(length) FROM streets);

external_knowledge:
- "paths that weave through the fabric" refers to streets;
- "city districts" are the subdivisions;
- "grand maps charting their territories" are the county maps;
- "whisper the identities of the cartographers and the architects" refers to the usernames of the creators of the subdivisions and county maps.

sql:
SELECT last_inspected AS Last_Inspection_Date, surface_type AS Surface_Type, traffic_volume AS Traffic_Volume
FROM streets
WHERE street_name = 'HANOVER LANE';

SELECT s.street_name, sub.subdivision_name, s.traffic_volume
FROM streets s
JOIN subdivisions sub ON s.subdivision_id = sub.subdivision_id;

SELECT COUNT(*) 
FROM streets 
WHERE surface_type = 'concrete' AND length > 500;

SELECT county_map_id, map_name, scale
FROM county_maps
WHERE scale = '1:10000' OR scale = '1:20000';

SELECT SUM(pl.budget) AS total_budget
FROM project_logs pl
WHERE pl.start_date > date('now', '-30 days');

SELECT s.street_name, s.length, sd.subdivision_name
FROM streets s
INNER JOIN subdivisions sd ON s.subdivision_id = sd.subdivision_id;

SELECT project_name 
FROM project_logs 
WHERE updated_date > 'specific_date';

SELECT DISTINCT street_name
FROM streets
WHERE length > 1200 AND surface_type = 'asphalt';

SELECT SUM(budget) AS total_budget
FROM project_logs
WHERE status = 'planning';
